noncompliant:
int *ptr = malloc(sizeof(int));
*ptr = 42;
free(ptr);
free(ptr); // Noncompliant: double free

char *buffer = malloc(100);
free(buffer);
// ... some code ...
free(buffer); // Noncompliant: releasing same memory twice

compliant:
int *ptr = malloc(sizeof(int));
*ptr = 42;
free(ptr);
ptr = NULL; // Compliant: set to NULL after free

char *buffer = malloc(100);
if (buffer != NULL) {
    free(buffer);
    buffer = NULL; // Compliant: prevent double free
}
